            if (firstByte == 192 && secondByte == 0 && thirdByte == 0) return true;
            // 192.0.2.0/24 (TEST-NET-1 documentation)
            if (firstByte == 192 && secondByte == 0 && thirdByte == 2) return true;
            // 198.18.0.0/15 (Network benchmarking)
