    private static final int READ_TIMEOUT = 5000; // 5 seconds read timeout
    private static final String DEFAULT_CHARSET = "UTF-8";
    private static final int MAX_REDIRECTS = 5; // Maximum number of redirects to follow

    public String getUrlContentPreview(String urlString) {
        if (urlString == null) {
            return "";
        }

        String currentUrl = urlString.trim();
        if (currentUrl.isEmpty()) {
            return "";
        }

        int redirectCount = 0;
        HttpURLConnection connection = null;

        try {
            while (redirectCount < MAX_REDIRECTS) {
                URL url = new URL(currentUrl);

                // Validate protocol to prevent access to non-HTTP resources (security measure)
                String protocol = url.getProtocol();
                if (!"http".equalsIgnoreCase(protocol) &&!"https".equalsIgnoreCase(protocol)) {
                    return "";
                }

                connection = (HttpURLConnection) url.openConnection();
                connection.setConnectTimeout(CONNECT_TIMEOUT);
                connection.setReadTimeout(READ_TIMEOUT);
                connection.setInstanceFollowRedirects(false); // Handle redirects manually for cross-protocol support

                // Set standard headers to avoid being blocked by servers
                connection.setRequestProperty("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36");
                connection.setRequestProperty("Accept-Encoding", "identity"); // Prefer uncompressed content

                int responseCode = connection.getResponseCode();

                if (responseCode >= 200 && responseCode < 300) {
                    String contentEncoding = connection.getContentEncoding();
                    String contentType = connection.getContentType();
                    String charset = DEFAULT_CHARSET;

                    // Extract charset from Content-Type header if available
                    if (contentType!= null) {
                        String[] parts = contentType.split(";");
                        for (String part : parts) {
                            part = part.trim();
                            if (part.toLowerCase().startsWith("charset=")) {
                                charset = part.substring("charset=".length()).trim();
                                break;
                            }
                        }
                    }

                    // Read content with gzip decompression support
                    try (InputStream is = connection.getInputStream();
                         InputStream streamToRead = (contentEncoding!= null && ("gzip".equalsIgnoreCase(contentEncoding) || "x-gzip".equalsIgnoreCase(contentEncoding)))
                                ? new GZIPInputStream(is) : is) {

                        byte[] buffer = new byte[MAX_BYTES];
                        int totalRead = 0;
                        int bytesRead;

                        while (totalRead < MAX_BYTES && (bytesRead = streamToRead.read(buffer, totalRead, MAX_BYTES - totalRead))!= -1) {
                            totalRead += bytesRead;
                        }

                        if (totalRead == 0) {
                            return "";
                        }

                        // Convert bytes to string with fallback for invalid charset
                        try {
                            return new String(buffer, 0, totalRead, charset);
                        } catch (UnsupportedEncodingException e) {
                            return new String(buffer, 0, totalRead, DEFAULT_CHARSET);
                        }
                    }
                } else if (isRedirect(responseCode)) {
                    // Handle redirect response
                    String location = connection.getHeaderField("Location");
                    if (location == null || location.trim().isEmpty()) {
                        return "";
                    }

                    // Resolve relative redirect URLs
                    URL newUrl = new URL(url, location);
                    currentUrl = newUrl.toString();
                    redirectCount++;

                    // Clean up current connection before next iteration
                    connection.disconnect();
                    connection = null;
                } else {
                    // Non-success, non-redirect response code
                    return "";
                }
            }

            // Exceeded maximum number of redirects
            return "";
        } catch (IOException | SecurityException e) {
            // All exceptions return empty string as required
            return "";
        } finally {
            // Ensure connection is always closed to prevent resource leaks
            if (connection!= null) {
                connection.disconnect();
            }
        }
    }

    /**
     * Check if the HTTP response code indicates a redirect that should be followed.
     */
    private boolean isRedirect(int responseCode) {
        return responseCode == HttpURLConnection.HTTP_MOVED_PERM
                || responseCode == HttpURLConnection.HTTP_MOVED_TEMP
                || responseCode == HttpURLConnection.HTTP_SEE_OTHER
                || responseCode == 307 // Temporary Redirect (HTTP 1.1)
                || responseCode == 308; // Permanent Redirect (RFC 7538)
    }
}
